import requests
from typing import Optional, Dict

def fetch_and_display_url_content(url: str, timeout: int = 30, headers: Optional[Dict[str, str]] = None) -> Optional[str]:
    try:
        print(f"Attempting to fetch URL: {url}")
        response = requests.get(url, timeout=timeout, headers=headers)
        response.raise_for_status()

        print(f"Successfully fetched URL: {url}")
        print(f"HTTP Status Code: {response.status_code}")
        print("\n--- URL Content Start ---")
        content = response.text
        print(content)
        print("--- URL Content End ---\n")
        return content

    except requests.exceptions.HTTPError as e:
        print(f"HTTP error occurred while fetching {url}: {e}")
        print(f"Status code: {e.response.status_code if e.response else 'N/A'}")
        return None
    except requests.exceptions.ConnectionError as e:
        print(f"Connection error occurred while fetching {url}: {e}")
        return None
    except requests.exceptions.Timeout as e:
        print(f"Timeout occurred while fetching {url} after {timeout} seconds: {e}")
        return None
    except requests.exceptions.RequestException as e:
        print(f"An unexpected request error occurred while fetching {url}: {e}")
        return None
    except Exception as e:
        print(f"An unexpected error occurred: {e}")
        return None